"use client";

import { motion } from "framer-motion";
import { GOLDEN_ANGLE, EASE_OUT } from "@/lib/phi";

/**
 * Phyllotaxis lotus — 21 petals (Fibonacci) placed using the golden angle.
 *
 * Each petal i sits at:
 *   r     = maxR × √(i/N)      — Vogel sunflower radial spacing
 *   θ     = i × 137.508°       — golden angle azimuth
 *
 * Petal orientation: tip points radially outward from center.
 * Petal base is the attachment point; scaleY unfolds from base → tip.
 *
 * Colors are CSS custom properties so the component reacts to
 * data-profile changes (Clear / Earth / Twilight) automatically.
 */

const N_PETALS = 21;

/**
 * Single lotus petal — base at (0,0), tip at (0,−h).
 * Sides bow outward in the lower third then taper to a point.
 */
function petalPath(w: number, h: number): string {
  const hw = w / 2;
  return [
    "M 0 0",
    `C ${-hw * 0.95} ${-h * 0.14} ${-hw * 1.15} ${-h * 0.48} ${-hw * 0.62} ${-h * 0.74}`,
    `C ${-hw * 0.22} ${-h * 0.91} 0 ${-h} 0 ${-h}`,
    `C 0 ${-h} ${hw * 0.22} ${-h * 0.91} ${hw * 0.62} ${-h * 0.74}`,
    `C ${hw * 1.15} ${-h * 0.48} ${hw * 0.95} ${-h * 0.14} 0 0`,
    "Z",
  ].join(" ");
}

interface LotusProps {
  size?: number;
  animate?: boolean;
  style?: React.CSSProperties;
}

export function Lotus({ size = 400, animate = true, style }: LotusProps) {
  const cx = size / 2;
  const cy = size / 2;
  const maxR = size * 0.33;

  const petals = Array.from({ length: N_PETALS }, (_, i) => {
    const t = (i + 1) / N_PETALS; // normalised 0→1 (centre→edge)

    // Vogel sunflower radial spacing
    const r = maxR * Math.sqrt(t);

    // Golden angle azimuth
    const angleDeg = i * GOLDEN_ANGLE;
    const angleRad = (angleDeg * Math.PI) / 180;

    // Petal base position
    const bx = cx + r * Math.cos(angleRad);
    const by = cy + r * Math.sin(angleRad);

    // Petal size scales with radial distance
    const sf = 0.28 + 0.72 * t;
    const pW = size * 0.058 * sf;
    const pH = size * 0.175 * sf;

    // Rotate so tip points outward.
    // Petal drawn pointing "up" (−y), standard angle 0 = rightward,
    // so rotate by (angleDeg + 90).
    const rotDeg = angleDeg + 90;

    // Stagger delay: inner petals first → outer last (unfolds outward)
    const delay = i * 0.06;

    return { bx, by, rotDeg, pW, pH, delay, t };
  });

  // Three colour bands: accent (inner) → accent-subtle (mid) → bg-muted (outer)
  function fill(t: number) {
    if (t < 0.38) return "var(--renge-color-accent)";
    if (t < 0.72) return "var(--renge-color-accent-subtle)";
    return "var(--renge-color-bg-muted)";
  }

  function fillOpacity(t: number) {
    return 0.82 - t * 0.28;
  }

  function strokeOpacity(t: number) {
    return 0.5 - t * 0.38;
  }

  // Render outer petals first so inner petals sit on top
  const renderOrder = [...petals].reverse();

  return (
    <svg
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      aria-hidden
      style={style}
    >
      {renderOrder.map((p, ri) => {
        const i = N_PETALS - 1 - ri; // original index for key
        return (
          // Plain <g> handles SVG positioning — no CSS transform conflict
          <g
            key={i}
            transform={`translate(${p.bx}, ${p.by}) rotate(${p.rotDeg})`}
          >
            {/*
             * motion.path handles the unfold animation.
             * transformBox fill-box + transformOrigin bottom
             * sets the scale pivot to the petal base (y = 0 in local space).
             */}
            <motion.path
              d={petalPath(p.pW, p.pH)}
              fill={fill(p.t)}
              fillOpacity={fillOpacity(p.t)}
              stroke="var(--renge-color-accent)"
              strokeWidth={0.5}
              strokeOpacity={strokeOpacity(p.t)}
              style={{
                transformBox: "fill-box",
                transformOrigin: "50% 100%",
              }}
              initial={animate ? { scaleY: 0, opacity: 0 } : undefined}
              animate={{ scaleY: 1, opacity: 1 }}
              transition={{
                scaleY: { duration: 0.85, delay: p.delay, ease: EASE_OUT },
                opacity: { duration: 0.4, delay: p.delay },
              }}
            />
          </g>
        );
      })}

      {/* Centre receptacle */}
      <motion.circle
        cx={cx}
        cy={cy}
        r={size * 0.022}
        fill="var(--renge-color-accent)"
        fillOpacity={0.9}
        style={{ transformBox: "fill-box", transformOrigin: "center" }}
        initial={animate ? { scale: 0 } : undefined}
        animate={{ scale: 1 }}
        transition={{ duration: 0.5, ease: EASE_OUT }}
      />
    </svg>
  );
}
